mapper.select:
SELECT o.*,
       (SELECT COUNT(*) FROM order_item WHERE order_id = o.id) AS item_count
FROM orders o WHERE o.id = #{id}

SELECT o.*,
       (SELECT COUNT(*) FROM order_item WHERE order_id = o.id) AS item_count
FROM orders o WHERE o.id = #{id} AND o.user_id = #{userId}

SELECT o.*,
       (SELECT COUNT(*) FROM order_item WHERE order_id = o.id) AS item_count
FROM orders o WHERE o.user_id = #{userId}

    AND o.status = #{status}

ORDER BY o.create_time DESC
LIMIT #{offset}, #{limit}
